('urbeld-cache-footer_pages_content', 'O:39:\"Illuminate\\Database\\Eloquent\\Collection\":2:{s:8:\"\0*\0items\";a:1:{i:0;O:15:\"App\\Models\\Page\":35:{s:13:\"\0*\0connection\";s:5:\"mysql\";s:8:\"\0*\0table\";s:5:\"pages\";s:13:\"\0*\0primaryKey\";s:2:\"id\";s:10:\"\0*\0keyType\";s:3:\"int\";s:12:\"incrementing\";b:1;s:7:\"\0*\0with\";a:0:{}s:12:\"\0*\0withCount\";a:0:{}s:19:\"preventsLazyLoading\";b:0;s:10:\"\0*\0perPage\";i:15;s:6:\"exists\";b:1;s:18:\"wasRecentlyCreated\";b:0;s:28:\"\0*\0escapeWhenCastingToString\";b:0;s:13:\"\0*\0attributes\";a:8:{s:2:\"id\";i:1;s:4:\"type\";s:7:\"content\";s:5:\"title\";s:21:\"{\"ar\": \"من نحن\"}\";s:7:\"content\";s:8230:\"{\"ar\": \"<!-- About Hero Section -->\\r\\n        <div class=\\\"about-hero-section-new pt-0\\\">\\r\\n            <div class=\\\"container\\\">\\r\\n                <div class=\\\"row align-items-center\\\">\\r\\n                    <div class=\\\"col-lg-12\\\">\\r\\n                        <div class=\\\"about-hero-left\\\">\\r\\n                            <a href=\\\"#\\\" class=\\\"btn-who-we-are wow fadeInUp\\\" data-wow-delay=\\\"0.1s\\\">\\r\\n                                <span>من نحن</span>\\r\\n                                <i class=\\\"bi bi-arrow-left\\\"></i>\\r\\n                            </a>\\r\\n                            <h1 class=\\\"about-hero-title-new wow fadeInUp\\\" data-wow-delay=\\\"0.2s\\\">تشكيل عالم المستقبل</h1>\\r\\n                            <div class=\\\"about-hero-description-wrapper wow fadeInUp\\\" data-wow-delay=\\\"0.3s\\\">\\r\\n                                <p class=\\\"about-hero-description-new\\\">\\r\\n                                    نحن سعداء لمشاركة المزيد معك، يرجى ملء هذا النموذج وسيعود فريقنا المخصص إليك قريباً.\\r\\n                                </p>\\r\\n                                <p class=\\\"about-hero-description-new\\\">\\r\\n                                    في المواد من الطاقة المتجددة والرياضة والترفيه، إلى مراكز البيانات والرعاية الصحية، نعمل\\r\\n                                    على\\r\\n                                    ضمان أن البيئة المبنية تترك تأثيراً إيجابياً دائماً. معاً، نسعى لجعل مشروعك أفضل مما\\r\\n                                    تصورت\\r\\n                                    أنه ممكن.\\r\\n                                </p>\\r\\n                            </div>\\r\\n                            <button type=\\\"button\\\" class=\\\" btn btn-icon py-3 px-5 animated fadeIn\\\">\\r\\n                                <span>قابل الفريق</span>\\r\\n                                <i class=\\\"icon-btn bi bi-arrow-up-left\\\"></i>\\r\\n                            </button>\\r\\n                        </div>\\r\\n                    </div>\\r\\n                    <div class=\\\"col-lg-12\\\">\\r\\n                        <div class=\\\"about-hero-image-wrapper-new wow fadeInUp\\\" data-wow-delay=\\\"0.5s\\\">\\r\\n                            <div class=\\\"statistics-cards-container\\\">\\r\\n                                <!-- Statistics Card 1 - Top -->\\r\\n                                <div class=\\\"statistics-card-new statistics-card-new-1\\\">\\r\\n                                    <div class=\\\"stat-card-label\\\">الخبرة المحلية</div>\\r\\n                                    <div class=\\\"stat-card-number\\\">\\r\\n                                        <span class=\\\"counter\\\" data-target=\\\"800\\\">0</span>+\\r\\n                                    </div>\\r\\n                                    <div class=\\\"stat-card-desc\\\">مشروع قيد التطوير</div>\\r\\n                                </div>\\r\\n                                <!-- Statistics Cards 2 & 3 - Bottom Row -->\\r\\n                                <div class=\\\"statistics-cards-row\\\">\\r\\n                                    <div class=\\\"statistics-card-new statistics-card-new-2\\\">\\r\\n                                        <div class=\\\"stat-card-label\\\">الخبرة المحلية</div>\\r\\n                                        <div class=\\\"stat-card-number\\\">\\r\\n                                            <span class=\\\"counter\\\" data-target=\\\"90\\\">0</span>m+\\r\\n                                        </div>\\r\\n                                        <div class=\\\"stat-card-desc\\\">قدم مربع من العقارات</div>\\r\\n                                    </div>\\r\\n                                    <div class=\\\"statistics-card-new statistics-card-new-3\\\">\\r\\n                                        <div class=\\\"stat-card-label\\\">الخبرة المحلية</div>\\r\\n                                        <div class=\\\"stat-card-number\\\">\\r\\n                                            <span class=\\\"counter\\\" data-target=\\\"500\\\">0</span>+\\r\\n                                        </div>\\r\\n                                        <div class=\\\"stat-card-desc\\\">إجمالي تكلفة المشاريع</div>\\r\\n                                    </div>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                    </div>\\r\\n                </div>\\r\\n            </div>\\r\\n        </div>\\r\\n\\r\\n        <!-- Our Story Timeline Section -->\\r\\n        <div class=\\\"our-story-section\\\">\\r\\n            <div class=\\\"container\\\">\\r\\n                <div class=\\\"row\\\">\\r\\n                    <div class=\\\"col-lg-12\\\">\\r\\n                        <div class=\\\"our-story-header\\\">\\r\\n                            <span class=\\\"our-story-label wow fadeInUp\\\" data-wow-delay=\\\"0.1s\\\">قصتنا</span>\\r\\n                            <h2 class=\\\"our-story-title wow fadeInUp\\\" data-wow-delay=\\\"0.2s\\\">أكثر من 40 عاماً من الرحلة\\r\\n                                الاستثنائية</h2>\\r\\n                        </div>\\r\\n                        <div class=\\\"our-story-timeline\\\">\\r\\n                            <div class=\\\"timeline-item-new wow fadeInUp\\\" data-wow-delay=\\\"0.3s\\\">\\r\\n                                <div class=\\\"timeline-year-new\\\">1995</div>\\r\\n                                <div class=\\\"timeline-image-wrapper\\\">\\r\\n                                    <img src=\\\"{{ asset(\'website/assets/img/state.png\') }}\\\" alt=\\\"1995 Project\\\" class=\\\"timeline-image\\\">\\r\\n                                </div>\\r\\n                                <div class=\\\"timeline-text\\\">\\r\\n                                    <p>انطلقنا برؤية واضحة لتحويل مفهوم التطوير العقاري في المنطقة. بدأنا بمشاريع صغيرة مع\\r\\n                                        التركيز على الجودة والابتكار في كل تفاصيل العمل.</p>\\r\\n                                </div>\\r\\n                            </div>\\r\\n\\r\\n                            <div class=\\\"timeline-item-new wow fadeInUp\\\" data-wow-delay=\\\"0.4s\\\">\\r\\n                                <div class=\\\"timeline-year-new\\\">2005</div>\\r\\n                                <div class=\\\"timeline-image-wrapper\\\">\\r\\n                                    <img src=\\\"{{ asset(\'website/assets/img/state.png\') }}\\\" alt=\\\"2005 Project\\\" class=\\\"timeline-image\\\">\\r\\n                                </div>\\r\\n                                <div class=\\\"timeline-text\\\">\\r\\n                                    <p>توسعنا بشكل كبير وبدأنا في تنفيذ مشاريع ضخمة. أصبحنا من الرواد في مجال التطوير\\r\\n                                        العقاري\\r\\n                                        المستدام والحلول البيئية المبتكرة.</p>\\r\\n                                </div>\\r\\n                            </div>\\r\\n\\r\\n                            <div class=\\\"timeline-item-new wow fadeInUp\\\" data-wow-delay=\\\"0.5s\\\">\\r\\n                                <div class=\\\"timeline-year-new\\\">2010</div>\\r\\n                                <div class=\\\"timeline-image-wrapper\\\">\\r\\n                                    <img src=\\\"{{ asset(\'website/assets/img/state.png\') }}\\\" alt=\\\"2010 Project\\\" class=\\\"timeline-image\\\">\\r\\n                                </div>\\r\\n                                <div class=\\\"timeline-text\\\">\\r\\n                                    <p>حققنا مكانة رائدة في السوق الإقليمي. نستمر في الابتكار وتبني أحدث التقنيات لضمان أفضل\\r\\n                                        النتائج لعملائنا وشركائنا في كل مشروع.</p>\\r\\n                                </div>\\r\\n                            </div>\\r\\n                        </div>\\r\\n                    </div>\\r\\n                </div>\\r\\n            </div>\\r\\n        </div>\"}\";s:10:\"target_url\";N;s:10:\"created_at\";s:19:\"2026-02-22 00:52:19\";s:10:\"updated_at\";s:19:\"2026-02-22 00:52:19\";s:4:\"slug\";s:8:\"about-us\";}s:11:\"\0*\0original\";a:8:{s:2:\"id\";i:1;s:4:\"type\";s:7:\"content\";s:5:\"title\";s:21:\"{\"ar\": \"من نحن\"}\";s:7:\"content\";s:8230:\"{\"ar\": \"<!-- About Hero Section -->\\r\\n        <div class=\\\"about-hero-section-new pt-0\\\">\\r\\n            <div class=\\\"container\\\">\\r\\n                <div class=\\\"row align-items-center\\\">\\r\\n                    <div class=\\\"col-lg-12\\\">\\r\\n                        <div class=\\\"about-hero-left\\\">\\r\\n                            <a href=\\\"#\\\" class=\\\"btn-who-we-are wow fadeInUp\\\" data-wow-delay=\\\"0.1s\\\">\\r\\n                                <span>من نحن</span>\\r\\n                                <i class=\\\"bi bi-arrow-left\\\"></i>\\r\\n                            </a>\\r\\n                            <h1 class=\\\"about-hero-title-new wow fadeInUp\\\" data-wow-delay=\\\"0.2s\\\">تشكيل عالم المستقبل</h1>\\r\\n                            <div class=\\\"about-hero-description-wrapper wow fadeInUp\\\" data-wow-delay=\\\"0.3s\\\">\\r\\n                                <p class=\\\"about-hero-description-new\\\">\\r\\n                                    نحن سعداء لمشاركة المزيد معك، يرجى ملء هذا النموذج وسيعود فريقنا المخصص إليك قريباً.\\r\\n                                </p>\\r\\n                                <p class=\\\"about-hero-description-new\\\">\\r\\n                                    في المواد من الطاقة المتجددة والرياضة والترفيه، إلى مراكز البيانات والرعاية الصحية، نعمل\\r\\n                                    على\\r\\n                                    ضمان أن البيئة المبنية تترك تأثيراً إيجابياً دائماً. معاً، نسعى لجعل مشروعك أفضل مما\\r\\n                                    تصورت\\r\\n                                    أنه ممكن.\\r\\n                                </p>\\r\\n                            </div>\\r\\n                            <button type=\\\"button\\\" class=\\\" btn btn-icon py-3 px-5 animated fadeIn\\\">\\r\\n                                <span>قابل الفريق</span>\\r\\n                                <i class=\\\"icon-btn bi bi-arrow-up-left\\\"></i>\\r\\n                            </button>\\r\\n                        </div>\\r\\n                    </div>\\r\\n                    <div class=\\\"col-lg-12\\\">\\r\\n                        <div class=\\\"about-hero-image-wrapper-new wow fadeInUp\\\" data-wow-delay=\\\"0.5s\\\">\\r\\n                            <div class=\\\"statistics-cards-container\\\">\\r\\n                                <!-- Statistics Card 1 - Top -->\\r\\n                                <div class=\\\"statistics-card-new statistics-card-new-1\\\">\\r\\n                                    <div class=\\\"stat-card-label\\\">الخبرة المحلية</div>\\r\\n                                    <div class=\\\"stat-card-number\\\">\\r\\n                                        <span class=\\\"counter\\\" data-target=\\\"800\\\">0</span>+\\r\\n                                    </div>\\r\\n                                    <div class=\\\"stat-card-desc\\\">مشروع قيد التطوير</div>\\r\\n                                </di