(1, NULL, '{\"ar\":\"المقاولات\",\"en\":\"Contracting\"}', '{\"ar\":\"يشمل شركات وأفراد متخصصين في خدمات البناء والإنشاء، مع احترافية وخبرة تضمن تلبية احتياجات العملاء في مجالات متعددة.\",\"en\":\"It includes companies and individuals specialized in construction and building services, with professionalism and expertise that ensure meeting clients\' needs in various fields.\"}', 'almkaolat', NULL, NULL, 1, '2026-02-20 20:54:20', '2026-03-07 14:54:28'),
(2, NULL, '{\"ar\":\"الاستشارات الهندسية\",\"en\":\"Engineering Consulting\"}', '{\"ar\":\"يشمل شركات وأفراد متخصصين في خدمات الاستشارات الهندسية، مع احترافية وخبرة تضمن تلبية احتياجات العملاء في مجالات متعددة.\",\"en\":\"It includes companies and individuals specialized in engineering consulting services, with professionalism and expertise that ensure meeting clients\' needs in various fields.\"}', 'alastsharat-alhndsy', NULL, NULL, 1, '2026-02-20 20:54:20', '2026-03-07 14:55:06'),
(3, NULL, '{\"ar\":\"الخدمات البيئية\",\"en\":\"Environmental Services\"}', '{\"ar\":\"يشمل شركات وأفراد متخصصين في خدمات البيئة، مع احترافية وخبرة تضمن تلبية احتياجات العملاء في مجالات متعددة.\",\"en\":\"It includes companies and individuals specialized in environmental services, with professionalism and expertise that ensure meeting clients\' needs in various fields.\"}', 'alkhdmat-albyyy', NULL, NULL, 1, '2026-02-20 20:54:20', '2026-03-07 14:53:45'),
