(27, 'home_commitments_list', NULL, '{\"ar\":\"[{\\\"title\\\":{\\\"ar\\\":\\\"\\\\u0627\\\\u0644\\\\u0645\\\\u0633\\\\u0624\\\\u0648\\\\u0644\\\\u064a\\\\u0629 \\\\u0627\\\\u0644\\\\u0645\\\\u0624\\\\u0633\\\\u0633\\\\u064a\\\\u0629\\\",\\\"en\\\":\\\"Corporate responsibility.\\\"},\\\"description\\\":{\\\"ar\\\":\\\"\\\\u0647\\\\u062f\\\\u0641\\\\u0646\\\\u0627 \\\\u0647\\\\u0648 \\\\u062a\\\\u062d\\\\u0642\\\\u064a\\\\u0642 \\\\u0635\\\\u0641\\\\u0631 \\\\u062d\\\\u0648\\\\u0627\\\\u062f\\\\u062b \\\\u0648\\\\u0645\\\\u0639\\\\u062f\\\\u0644 \\\\u062a\\\\u0643\\\\u0631\\\\u0627\\\\u0631 \\\\u0641\\\\u0642\\\\u062f\\\\u0627\\\\u0646 \\\\u0627\\\\u0644\\\\u0648\\\\u0642\\\\u062a \\\\u0644\\\\u062f\\\\u064a\\\\u0646\\\\u0627 \\\\u064a\\\\u0642\\\\u0648\\\\u062f \\\\u0627\\\\u0644\\\\u0635\\\\u0646\\\\u0627\\\\u0639\\\\u0629.\\\",\\\"en\\\":\\\"Our goal is to achieve zero accidents, and our lost time recurrence rate leads the industry.\\\"},\\\"image\\\":\\\"\\\\/storage\\\\/32\\\\/why-us1.png\\\"},{\\\"title\\\":{\\\"ar\\\":\\\"\\\\u062e\\\\u0628\\\\u0631\\\\u0627\\\\u0621 \\\\u0628\\\\u0631\\\\u0648\\\\u062d \\\\u0627\\\\u0644\\\\u0641\\\\u0631\\\\u064a\\\\u0642\\\",\\\"en\\\":\\\"Team-oriented experts\\\"},\\\"description\\\":{\\\"ar\\\":\\\"\\\\u0647\\\\u062f\\\\u0641\\\\u0646\\\\u0627 \\\\u0647\\\\u0648 \\\\u062a\\\\u062d\\\\u0642\\\\u064a\\\\u0642 \\\\u0635\\\\u0641\\\\u0631 \\\\u062d\\\\u0648\\\\u0627\\\\u062f\\\\u062b \\\\u0648\\\\u0645\\\\u0639\\\\u062f\\\\u0644 \\\\u062a\\\\u0643\\\\u0631\\\\u0627\\\\u0631 \\\\u0641\\\\u0642\\\\u062f\\\\u0627\\\\u0646 \\\\u0627\\\\u0644\\\\u0648\\\\u0642\\\\u062a \\\\u0644\\\\u062f\\\\u064a\\\\u0646\\\\u0627 \\\\u064a\\\\u0642\\\\u0648\\\\u062f \\\\u0627\\\\u0644\\\\u0635\\\\u0646\\\\u0627\\\\u0639\\\\u0629.\\\",\\\"en\\\":\\\"Our goal is to achieve zero accidents, and our lost time incident rate leads the industry.\\\"},\\\"image\\\":\\\"\\\\/storage\\\\/33\\\\/why-us2.png\\\"},{\\\"title\\\":{\\\"ar\\\":\\\"\\\\u0627\\\\u0644\\\\u062a\\\\u0646\\\\u0648\\\\u0639 \\\\u0648\\\\u0627\\\\u0644\\\\u0645\\\\u0633\\\\u0627\\\\u0648\\\\u0627\\\\u0629 \\\\u0648\\\\u0627\\\\u0644\\\\u0634\\\\u0645\\\\u0648\\\\u0644\\\",\\\"en\\\":\\\"Diversity, equality, and inclusion\\\"},\\\"description\\\":{\\\"ar\\\":\\\"\\\\u0647\\\\u062f\\\\u0641\\\\u0646\\\\u0627 \\\\u0647\\\\u0648 \\\\u062a\\\\u062d\\\\u0642\\\\u064a\\\\u0642 \\\\u0635\\\\u0641\\\\u0631 \\\\u062d\\\\u0648\\\\u0627\\\\u062f\\\\u062b \\\\u0648\\\\u0645\\\\u0639\\\\u062f\\\\u0644 \\\\u062a\\\\u0643\\\\u0631\\\\u0627\\\\u0631 \\\\u0641\\\\u0642\\\\u062f\\\\u0627\\\\u0646 \\\\u0627\\\\u0644\\\\u0648\\\\u0642\\\\u062a \\\\u0644\\\\u062f\\\\u064a\\\\u0646\\\\u0627 \\\\u064a\\\\u0642\\\\u0648\\\\u062f \\\\u0627\\\\u0644\\\\u0635\\\\u0646\\\\u0627\\\\u0639\\\\u0629.\\\",\\\"en\\\":\\\"Our goal is to achieve zero accidents, and our lost time frequency rate leads the industry.\\\"},\\\"image\\\":\\\"\\\\/storage\\\\/34\\\\/why-us3.png\\\"}]\"}', '2026-02-21 00:09:18', '2026-03-07 15:02:00'),
(28, 'home_about_list', NULL, '{\"ar\":\"[{\\\"title\\\":{\\\"ar\\\":\\\"\\\\u0627\\\\u0644\\\\u0645\\\\u0643\\\\u0627\\\\u0646 \\\\u0627\\\\u0644\\\\u0623\\\\u0648\\\\u0644 \\\\u0644\\\\u0644\\\\u0639\\\\u062b\\\\u0648\\\\u0631 \\\\u0639\\\\u0644\\\\u0649 \\\\u0627\\\\u0644\\\\u0639\\\\u0642\\\\u0627\\\\u0631 \\\\u0627\\\\u0644\\\\u0645\\\\u062b\\\\u0627\\\\u0644\\\\u064a\\\",\\\"en\\\":\\\"The first place to find the perfect property\\\"},\\\"description\\\":{\\\"ar\\\":\\\"\\\\u0646\\\\u062d\\\\u0646 \\\\u0646\\\\u0633\\\\u0627\\\\u0639\\\\u062f\\\\u0643 \\\\u0641\\\\u064a \\\\u0627\\\\u0644\\\\u0639\\\\u062b\\\\u0648\\\\u0631 \\\\u0639\\\\u0644\\\\u0649 \\\\u0645\\\\u0646\\\\u0632\\\\u0644 \\\\u0623\\\\u062d\\\\u0644\\\\u0627\\\\u0645\\\\u0643 \\\\u0645\\\\u0646 \\\\u062e\\\\u0644\\\\u0627\\\\u0644 \\\\u062e\\\\u062f\\\\u0645\\\\u0627\\\\u062a\\\\u0646\\\\u0627 \\\\u0627\\\\u0644\\\\u0645\\\\u062a\\\\u0645\\\\u064a\\\\u0632\\\\u0629. \\\\u0646\\\\u0648\\\\u0641\\\\u0631 \\\\u0644\\\\u0643 \\\\u0645\\\\u062c\\\\u0645\\\\u0648\\\\u0639\\\\u0629 \\\\u0648\\\\u0627\\\\u0633\\\\u0639\\\\u0629 \\\\u0645\\\\u0646 \\\\u0627\\\\u0644\\\\u062e\\\\u064a\\\\u0627\\\\u0631\\\\u0627\\\\u062a \\\\u0627\\\\u0644\\\\u0639\\\\u0642\\\\u0627\\\\u0631\\\\u064a\\\\u0629 \\\\u0627\\\\u0644\\\\u062a\\\\u064a \\\\u062a\\\\u0646\\\\u0627\\\\u0633\\\\u0628 \\\\u0627\\\\u062d\\\\u062a\\\\u064a\\\\u0627\\\\u062c\\\\u0627\\\\u062a\\\\u0643 \\\\u0648\\\\u0645\\\\u064a\\\\u0632\\\\u0627\\\\u0646\\\\u064a\\\\u062a\\\\u0643. \\\\u0646\\\\u0644\\\\u062a\\\\u0632\\\\u0645 \\\\u0628\\\\u062a\\\\u0642\\\\u062f\\\\u064a\\\\u0645 \\\\u0623\\\\u0641\\\\u0636\\\\u0644 \\\\u062a\\\\u062c\\\\u0631\\\\u0628\\\\u0629 \\\\u0639\\\\u0642\\\\u0627\\\\u0631\\\\u064a\\\\u0629 \\\\u0644\\\\u0639\\\\u0645\\\\u0644\\\\u0627\\\\u0626\\\\u0646\\\\u0627\\\",\\\"en\\\":\\\"We help you find your dream home through our exceptional services. We offer you a wide range of real estate options that suit your needs and budget